import React, { useState, useEffect } from 'react';
import './App.css';

const escapeHtml = (text) => {
  return text
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;')
    .replace(/'/g, '&#39;');
};

const markdownToHtml = (text) => {
  let escaped = escapeHtml(text);
  escaped = escaped.replace(/\*\*(.*?)\*\*/g, '<strong>$1</strong>');
  escaped = escaped.replace(/\*(.*?)\*/g, '<em>$1</em>');
  escaped = escaped.replace(/\[(.*?)\]\((.*?)\)/g, '<a href="$2" target="_blank" rel="noopener noreferrer">$1</a>');
  escaped = escaped.replace(/\n/g, '<br>');
  return escaped;
};

const getFirstLine = (content) => {
  return content.split('\n')[0];
};

const NoteSidebar = ({ notes, selectedNoteId, onSelectNote, onDeleteNote, searchQuery, onSearchChange, onAddNote }) => {
  const filteredNotes = notes.filter(note =>
    note.title.toLowerCase().includes(searchQuery.toLowerCase()) ||
    note.content.toLowerCase().includes(searchQuery.toLowerCase())
  );

  return (
    <div className="sidebar">
      <div className="sidebar-header">
        <h2>My Notes</h2>
        <button className="new-note-btn" onClick={onAddNote}>+ New Note</button>
      </div>
      <input
        type="text"
        placeholder="Search notes..."
        value={searchQuery}
        onChange={(e) => onSearchChange(e.target.value)}
        className="search-input"
      />
      <div className="notes-list">
        {filteredNotes.length === 0 && <div className="no-notes">No notes found</div>}
        {filteredNotes.map(note => (
          <div
            key={note.id}
            className={`note-item ${selectedNoteId === note.id ? 'active' : ''}`}
            onClick={() => onSelectNote(note.id)}
          >
            <div className="note-title">{note.title || 'Untitled'}</div>
            <div className="note-preview">{getFirstLine(note.content) || 'No content'}</div>
            <button
              className="delete-note-btn"
              onClick={(e) => {
                e.stopPropagation();
                onDeleteNote(note.id);
              }}
            >
              🗑️
            </button>
          </div>
        ))}
      </div>
    </div>
  );
};

const NoteEditor = ({ note, onUpdateNote, onDeleteNote }) => {
  const [previewMode, setPreviewMode] = useState(false);

  if (!note) {
    return (
      <div className="editor-placeholder">
        <p>Select a note or create a new one</p>
      </div>
    );
  }

  const handleTitleChange = (e) => {
    onUpdateNote({ ...note, title: e.target.value });
  };

  const handleContentChange = (e) => {
    onUpdateNote({ ...note, content: e.target.value });
  };

  return (
    <div className="editor">
      <div className="editor-header">
        <input
          type="text"
          value={note.title}
          onChange={handleTitleChange}
          placeholder="Note title"
          className="title-input"
        />
        <div className="editor-actions">
          <button
            className="delete-btn"
            onClick={() => onDeleteNote(note.id)}
          >
            Delete Note
          </button>
          <button
            className="preview-toggle"
            onClick={() => setPreviewMode(!previewMode)}
          >
            {previewMode ? 'Edit' : 'Preview'}
          </button>
        </div>
      </div>
      <div className="editor-date">
        Created: {new Date(note.createdAt).toLocaleString()}
      </div>
      {previewMode ? (
        <div
          className="markdown-preview"
          dangerouslySetInnerHTML={{ __html: markdownToHtml(note.content) }}
        />
      ) : (
        <textarea
          value={note.content}
          onChange={handleContentChange}
          placeholder="Write your note here... Use **bold**, *italic*, [links](http://example.com)"
          className="content-textarea"
        />
      )}
      {!previewMode && (
        <div className="markdown-hint">
          Tip: **bold**, *italic*, [link text](url)
        </div>
      )}
    </div>
  );
};

const App = () => {
  const [notes, setNotes] = useState([]);
  const [searchQuery, setSearchQuery] = useState('');
  const [selectedNoteId, setSelectedNoteId] = useState(null);

  useEffect(() => {
    const savedNotes = localStorage.getItem('notes-app');
    if (savedNotes) {
      try {
        const parsed = JSON.parse(savedNotes);
        setNotes(parsed);
        if (parsed.length > 0) setSelectedNoteId(parsed[0].id);
      } catch (e) {}
    }
  }, []);

  useEffect(() => {
    localStorage.setItem('notes-app', JSON.stringify(notes));
  }, [notes]);

  const addNote = () => {
    const newNote = {
      id: Date.now(),
      title: 'Untitled',
      content: '',
      createdAt: Date.now()
    };
    setNotes(prev => [newNote, ...prev]);
    setSelectedNoteId(newNote.id);
  };

  const updateNote = (updatedNote) => {
    setNotes(prev => prev.map(note => note.id === updatedNote.id ? updatedNote : note));
  };

  const deleteNote = (id) => {
    if (window.confirm('Are you sure you want to delete this note?')) {
      setNotes(prev => prev.filter(note => note.id !== id));
      if (selectedNoteId === id) {
        const remaining = notes.filter(note => note.id !== id);
        setSelectedNoteId(remaining.length > 0 ? remaining[0].id : null);
      }
    }
  };

  const selectedNote = notes.find(note => note.id === selectedNoteId) || null;

  return (
    <div className="app-container">
      <NoteSidebar
        notes={notes}
        selectedNoteId={selectedNoteId}
        onSelectNote={setSelectedNoteId}
        onDeleteNote={deleteNote}
        searchQuery={searchQuery}
        onSearchChange={setSearchQuery}
        onAddNote={addNote}
      />
      <NoteEditor
        note={selectedNote}
        onUpdateNote={updateNote}
        onDeleteNote={deleteNote}
      />
    </div>
  );
};

export default App;
